)

mapper.delete:
BEGIN

    DELETE FROM TBL_RADAR_SCORE WHERE LOG_RESULT_ID IN (SELECT ID FROM TBL_LOG_RESULT WHERE LOG_ID IN #{id});
    DELETE FROM TBL_LOG_PATTERN WHERE LOG_RESULT_ID IN (SELECT ID FROM TBL_LOG_RESULT WHERE LOG_ID IN #{id});
    DELETE FROM TBL_LOG_ACTION_PLAN WHERE LOG_RESULT_ID IN (SELECT ID FROM TBL_LOG_RESULT WHERE LOG_ID IN #{id});


    DELETE FROM TBL_CHECKLIST WHERE PROJECT_ID IN (SELECT ID FROM TBL_PROJECT WHERE LOG_ID IN #{id});
    DELETE FROM TBL_SUGGESTION WHERE PROJECT_ID IN (SELECT ID FROM TBL_PROJECT WHERE LOG_ID IN #{id});


    DELETE FROM TBL_LOG_RESULT WHERE LOG_ID IN #{id};
    DELETE FROM TBL_LOG_LIKE WHERE LOG_ID IN #{id};
    DELETE FROM TBL_PROJECT WHERE LOG_ID IN #{id};


    DELETE FROM TBL_LOG WHERE ID IN #{id};
END;
